#include<bits/stdc++.h>
using namespace std;
#define pii pair<int,int>
#define inf 1000000000
#define int long long
const int maxn=3e3+5;
struct node {
	vector<pii>e;
	int d=inf,cs=0,b=0,h=inf;
} v[maxn];
queue<int>q;
priority_queue<pii,vector<pii>,greater<pii>>pq;
int n,m,flag;
void cheek_s(int h,int id) {
	if(h<v[id].h) {
		v[id].h=h;
		if(!v[id].b) {
			q.push(id);
			v[id].b=1;
			if(++v[id].cs>n) {
				flag=1;
			}
		}
	}
}
void spfa() {
	for(int i=1; i<=n; i++) {
		v[0].e.emplace_back(i,0);
	}
	cheek_s(0,0);
	while(!q.empty()&&!flag) {
		int id=q.front();
		q.pop();
		v[id].b=0;
		for(auto&e:v[id].e) {
			cheek_s(v[id].h+e.second,e.first);
			if(flag)break;
		}
	}
}
void dijkstra(int s) {
	for(int i=1; i<=n; i++) {
		v[i].d=inf;
		v[i].b=0;
	}
	v[s].d=0;
	pq.push({0,s});
	while(!pq.empty()) {
		auto top=pq.top();
		pq.pop();
		int u=top.second;
		if(v[u].b)continue;
		v[u].b=1;
		for(auto&e:v[u].e) {
			int v_node=e.first;
			int w=e.second;
			if(v[u].d+w<v[v_node].d) {
				v[v_node].d=v[u].d+w;
				pq.push({v[v_node].d,v_node});
			}
		}
	}
	int res=0;
	for(int j=1; j<=n; j++) {
		if(s==j) {
			res+=0;
		} else if(v[j].d==inf) {
			res+=j*inf;
		} else {
			res+=j*(v[j].d-(v[s].h-v[j].h));
		}
	}
	cout<<res<<"\n";
}
signed main() {
	ios::sync_with_stdio(false);
	cin.tie(0);
	cin>>n>>m;
	for(int i=1,x,y,z; i<=m; i++) {
		cin>>x>>y>>z;
		v[x].e.emplace_back(y,z);
	}
	spfa();
	if(flag) {
		cout<<-1<<"\n";
		return 0;
	}
	for(int i=1; i<=n; i++) {
		for(auto&j:v[i].e) {
			j.second+=v[i].h-v[j.first].h;
		}
	}
	for(int i=1; i<=n; i++) {
		dijkstra(i);
	}
	return 0;
}
